using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(b =>
        {
            // Fix 1: EF Core 9 renamed the discriminator property from "Discriminator" to "$type".
            // Keep the old name so existing documents and raw SQL queries still work.
            b.HasDiscriminator<string>("Discriminator");

            // Fix 2: EF Core 9 stores just the key in JSON "id" instead of "{Discriminator}|{Key}".
            // A value converter preserves the old compound format for existing documents.
            b.Property(e => e.Id)
                .HasConversion(
                    v => "Blog|" + v,
                    v => v.StartsWith("Blog|") ? v.Substring(5) : v);

            // Fix 3: HasIndex now throws for the Cosmos provider (was silently ignored in EF Core 8).
            // REMOVED: b.HasIndex(b => b.Name);
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

